import React, { useEffect, useState } from "react";
import "./nhanvien.css";
import { fetchWithAuth } from "../../helper/fetchWithAuth";

function Nhanvien() {
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [editUser, setEditUser] = useState(null); // User đang chỉnh sửa
  const [openmodal, setmodal] = useState(false); // Modal thêm/sửa
  const [newusers, setNewusers] = useState({
    id: "",
    name: "",
    username: "",
    password: "",
    role: "",
    phonenumber: "",
    email: "",
    address: "",
    salary: "",
    salarybonus: "",
    defaultsalary: "",
    carsoldtotal: "",
  });

  // Tải danh sách nhân viên
  const fetchEmployees = async () => {
    try {
      const employees = await fetchWithAuth("/api/employees", "GET");
      setCustomers(employees); // Cập nhật danh sách
    } catch (error) {
      console.error("Lỗi khi tải danh sách nhân viên:", error);
      setError(error.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEmployees();
  }, []);

  // Xử lý thêm hoặc cập nhật nhân viên
  const handleAddOrUpdateEmployee = async (e) => {
    e.preventDefault();
    const url = editUser
      ? `/api/employees/${editUser.id}` // Cập nhật
      : "/api/employees"; // Thêm mới
    const method = editUser ? "PUT" : "POST";

    try {
      await fetchWithAuth(url, method, newusers);
      fetchEmployees(); // Tải lại danh sách
      setmodal(false); // Đóng modal
      setEditUser(null); // Reset chế độ chỉnh sửa
    } catch (error) {
      console.error(`Lỗi khi ${editUser ? "cập nhật" : "thêm"} nhân viên:`, error);
      setError(error.message);
    }

    // Reset form
    setNewusers({
      id: "",
      name: "",
      username: "",
      password: "",
      role: "",
      phonenumber: "",
      email: "",
      address: "",
      salary: "",
      salarybonus: "",
      defaultsalary: "",
      carsoldtotal: "",
    });
  };

  // Xử lý xóa nhân viên
  const handleDelete = async (id) => {
    if (!window.confirm("Bạn có chắc chắn muốn xóa nhân viên này không?")) return;

    try {
      await fetchWithAuth(`/api/employees/${id}`, "DELETE");
      fetchEmployees(); // Tải lại danh sách
    } catch (error) {
      console.error("Lỗi khi xóa nhân viên:", error);
      setError(error.message);
    }
  };

  // Xử lý chỉnh sửa nhân viên
  const handleEdit = (user) => {
    setEditUser(user); // Gán user đang chỉnh sửa
    setNewusers(user); // Load dữ liệu user vào form
    setmodal(true); // Mở modal
  };

  // Xử lý thay đổi input
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewusers({ ...newusers, [name]: value });
  };

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Lỗi: {error}</p>;

  return (
    <div className="customer-table">
      <h2>Bảng Nhân Viên</h2>
      <button onClick={() => setmodal(true)} style={{ cursor: "pointer" }}>
        + Nhân viên mới
      </button>
      {openmodal && (
        <form onSubmit={handleAddOrUpdateEmployee} className="add-customer-form">
          <div className="add-customer-form--body">
            <input
              type="text"
              name="name"
              placeholder="Tên nhân viên"
              value={newusers.name}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="username"
              placeholder="Tên đăng nhập"
              value={newusers.username}
              onChange={handleInputChange}
              required
            />
            {!editUser && (
              <input
                type="password"
                name="password"
                placeholder="Mật khẩu"
                value={newusers.password}
                onChange={handleInputChange}
                required
              />
            )}
            <input
              type="text"
              name="role"
              placeholder="Chức vụ"
              value={newusers.role}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="phonenumber"
              placeholder="Số điện thoại"
              value={newusers.phonenumber}
              onChange={handleInputChange}
              required
            />
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={newusers.email}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="address"
              placeholder="Địa chỉ"
              value={newusers.address}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="salary"
              placeholder="Lương"
              value={newusers.salary}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="salarybonus"
              placeholder="Lương thưởng"
              value={newusers.salarybonus}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="defaultsalary"
              placeholder="Lương mặc định"
              value={newusers.defaultsalary}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="carsoldtotal"
              placeholder="Số xe bán được"
              value={newusers.carsoldtotal}
              onChange={handleInputChange}
              required
            />
            <div className="group-btn">
              <button type="submit">{editUser ? "Cập nhật" : "Thêm"}</button>
              <button
                type="button"
                onClick={() => {
                  setmodal(false);
                  setEditUser(null);
                }}
              >
                Hủy
              </button>
            </div>
          </div>
        </form>
      )}

      <table>
        <thead>
          <tr>
            <th>Tên nhân viên</th>
            <th>Chức vụ</th>
            <th>SDT</th>
            <th>Email</th>
            <th>Địa chỉ</th>
            <th>Lương</th>
            <th>Lương thưởng</th>
            <th>Lương mặc định</th>
            <th>Số xe bán được</th>
            <th>Thay đổi</th>
          </tr>
        </thead>
        <tbody>
          {customers.map((user) => (
            <tr key={user.id}>
              <td>{user.name}</td>
              <td>{user.role}</td>
              <td>{user.phonenumber}</td>
              <td>{user.email}</td>
              <td>{user.address}</td>
              <td>{user.salary}</td>
              <td>{user.salarybonus}</td>
              <td>{user.defaultsalary}</td>
              <td>{user.carsoldtotal}</td>
              <td>
                <button onClick={() => handleEdit(user)}>Sửa</button>
                <button onClick={() => handleDelete(user.id)}>Xóa</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Nhanvien;
